mapper.select:
SELECT 
FROM notification_receiver


        AND id = #{id}


        AND notice_id = #{noticeId}



        AND receiver_id = #{receiverId}


        AND receiver_role = #{receiverRole}


        AND read_status = #{readStatus}



        AND read_time >=#{readTimeStart}


        AND read_time <=#{readTimeEnd}


        AND create_time >=#{createTimeStart}


        AND create_time <= #{createTimeEnd}



        AND notice_id IN #{item}


ORDER BY create_time DESC

update.foreach:
UPDATE notification_receiver
notice_id = #{item.noticeId}, receiver_id = #{item.receiverId}, receiver_role = #{item.receiverRole}, read_status = #{item.readStatus}, read_time = #{item.readTime}, update_time = NOW()
WHERE id = #{item.id}

mapper.update:
UPDATE notification_receiver
SET read_status = 'READ', read_time = NOW(), update_time = NOW()
WHERE id = #{id}
